function formatSavings(value, unit) {
    if (!unit) return String(value);
    if (unit === 'ms') {
        if (value >= 1000) {
            return `${(value / 1000).toFixed(1)} s`;
        }
        return `${Math.round(value)} ms`;
    }
    if (unit === 'bytes') {
        if (value >= 1024 * 1024) {
            return `${(value / (1024 * 1024)).toFixed(1)} MB`;
        }
        if (value >= 1024) {
            return `${(value / 1024).toFixed(1)} KB`;
        }
        return `${value} B`;
    }
    return String(value);
}
